from pathlib import Path
import pandas as pd

input_specs = [
    {
        "path": "/workspace/input/attachments/time_entries.csv",
        "logical_path": "attachments/time_entries.csv",
        "declared_columns": [
            "time_entry_id", "employee_id", "contract_ref", "work_date",
            "hours_logged", "billed_rate", "billed_amount", "invoice_id", "project_code"
        ],
        "type_expectations": {
            "work_date": "date",
            "hours_logged": "numeric",
            "billed_rate": "numeric",
            "billed_amount": "numeric",
        },
    },
    {
        "path": "/workspace/input/attachments/rates.csv",
        "logical_path": "attachments/rates.csv",
        "declared_columns": [
            "contract_id", "role_code", "hourly_rate", "effective_date", "expiration_date"
        ],
        "type_expectations": {
            "hourly_rate": "numeric",
            "effective_date": "date",
            "expiration_date": "date",
        },
    },
]

NULL_TOKENS = {"", "null", "none", "nan", "na"}

def read_csv(path: str) -> pd.DataFrame:
    print(f"Loading {path}...", flush=True)
    try:
        return pd.read_csv(path, dtype=str, keep_default_na=False)
    except Exception as e:
        raise RuntimeError(f"Failed to read CSV {path}: {e}") from e


def null_mask(series: pd.Series) -> pd.Series:
    s = series.astype("string")
    stripped = s.str.strip()
    lowered = stripped.str.lower()
    return stripped.eq("") | lowered.isin(NULL_TOKENS)


def sample_invalid(values: pd.Series, limit: int = 5):
    vals = values.astype("string").str.strip()
    vals = vals[vals.ne("")]
    return [v for v in vals.head(limit).tolist()]

profiles = []
for spec in input_specs:
    df = read_csv(spec["path"])
    observed_columns = list(df.columns)
    row_count = int(len(df))

    missing_columns = [c for c in spec["declared_columns"] if c not in observed_columns]
    extra_columns = [c for c in observed_columns if c not in spec["declared_columns"]]
    ordered_match = observed_columns == spec["declared_columns"]
    schema_status = "match" if not missing_columns and not extra_columns and ordered_match else "mismatch"

    schema_validation = {
        "status": schema_status,
        "declared_columns": spec["declared_columns"],
        "observed_columns": observed_columns,
        "missing_columns": missing_columns,
        "extra_columns": extra_columns,
        "ordered_match": ordered_match,
    }

    null_findings = []
    for col in observed_columns:
        mask = null_mask(df[col])
        null_count = int(mask.sum())
        null_findings.append({
            "column": col,
            "null_count": null_count,
            "status": "has_nulls" if null_count > 0 else "clean",
            "null_rate": round(null_count / row_count, 6) if row_count else 0.0,
        })

    type_mismatch_findings = []
    for col, expected_type in spec["type_expectations"].items():
        if col not in df.columns:
            type_mismatch_findings.append({
                "column": col,
                "expected_type": expected_type,
                "status": "missing_column",
                "non_null_count": None,
                "invalid_count": None,
                "sample_invalid_values": [],
            })
            continue

        mask = null_mask(df[col])
        non_null = df.loc[~mask, col]
        if expected_type == "numeric":
            parsed = pd.to_numeric(non_null, errors="coerce")
            invalid_mask = parsed.isna()
        elif expected_type == "date":
            parsed = pd.to_datetime(non_null, errors="coerce")
            invalid_mask = parsed.isna()
        else:
            invalid_mask = pd.Series([False] * len(non_null), index=non_null.index)

        invalid_count = int(invalid_mask.sum())
        type_mismatch_findings.append({
            "column": col,
            "expected_type": expected_type,
            "status": "mismatch" if invalid_count > 0 else "ok",
            "non_null_count": int(non_null.shape[0]),
            "invalid_count": invalid_count,
            "sample_invalid_values": sample_invalid(non_null[invalid_mask]),
        })

    profiles.append({
        "path": spec["logical_path"],
        "row_count": row_count,
        "schema_validation": schema_validation,
        "null_findings": null_findings,
        "type_mismatch_findings": type_mismatch_findings,
    })

profile = {"files": profiles}

out_path = Path("/workspace/output/schema_profile2.json")
out_path.parent.mkdir(parents=True, exist_ok=True)
print(f"Writing {out_path}...", flush=True)
with out_path.open("w", encoding="utf-8") as f:
    json.dump(profile, f, ensure_ascii=False, indent=2)
    f.write("\n")

# verify output exists and is non-empty and valid JSON
size = out_path.stat().st_size
assert size > 0, "output/schema_profile2.json was written but is empty"
with out_path.open("r", encoding="utf-8") as f:
    loaded = json.load(f)
assert isinstance(loaded, dict), f"Expected top-level JSON object, got {type(loaded).__name__}"
assert "files" in loaded and len(loaded["files"]) == 2, "Profile must include both files"
print(json.dumps({
    "verification": {
        "path": str(out_path),
        "exists": out_path.exists(),
        "size_bytes": size,
        "files_profiled": [item["path"] for item in loaded["files"]],
        "row_counts": {item["path"]: item["row_count"] for item in loaded["files"]},
    }
}, indent=2), flush=True)
